public static long solve(long[] weight) {
    long count = 0;
    int start = 0;
    long currentMax = 0;
    for (int i = 0; i < weight.length; i++) {
        if (i >= start) {
            currentMax = Math.max(currentMax, weight[i]);
            if (currentMax > weight[i]) {
                count++;
                start = i + 1;
                currentMax = 0;
            }
        }
    }
    return count;
}
